@import "tailwindcss";

@theme inline {
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--font-sans: var(--font-geist-sans);
	--font-mono: var(--font-geist-mono);
}

:root {
	--background: #f7f7f7;
	--foreground: #131313;

	--color-hero-card: #d0e9fb;
	--color-accent-blue: #50a8e4;
	--color-dark: #262424;
	--color-white: #ffffff;
	--color-muted: #505050;
}

*,
*::before,
*::after {
	box-sizing: border-box;
}

body {
	background: var(--background);
	color: var(--foreground);
	-webkit-font-smoothing: antialiased;
}

.section {
	background: #f7f7f7;
	padding: 80px 52px;
}

.container {
	max-width: 1176px;
	margin-inline: auto;
	display: flex;
	flex-direction: column;
	gap: 64px;
}

.header {
	display: flex;
	align-items: flex-end;
	justify-content: space-between;
	gap: 40px;
}

.headingGroup {
	display: flex;
	flex-direction: column;
	gap: 16px;
}

.badge {
	align-self: flex-start;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	height: 28px;
	padding: 0 16px;
	border-radius: 28px;
	background: #fff;
	font-size: 12px;
	letter-spacing: 1.44px;
	line-height: 1.333;
	color: #131313;
}

.header h2 {
	max-width: 576px;
	font-size: 64px;
	font-weight: 500;
	line-height: 1.125;
	letter-spacing: -2.56px;
	color: #262424;
}

.header p {
	max-width: 375px;
	font-size: 16px;
	line-height: 1.5;
	color: #505050;
}

.grid {
	display: grid;
	grid-template-columns: repeat(3, minmax(0, 1fr));
	gap: 24px;
	align-items: stretch;
	height: 444px;
}

.column {
	display: grid;
	grid-template-rows: 84px 1fr;
	gap: 24px;
	min-height: 0;
}

.column:last-child {
	grid-template-rows: 1fr 84px;
}

.card {
	min-height: 84px;
	padding: 24px;
	border-radius: 24px;
	background: #fff;
	display: flex;
	flex-direction: column;
	justify-content: space-between;
	gap: 80px;
	color: #262424;
}

.card:has(.trustAvatars),
.card:has(.timerRow) {
	height: 84px;
	min-height: 84px;
	justify-content: center;
	gap: 0;
}

.card:has(.trustAvatars) {
	flex-direction: row;
	align-items: center;
	justify-content: space-between;
}

.tall {
	height: 444px;
	min-height: 444px;
}

.dark {
	background: #262424;
	color: #fff;
}

.cardText {
	font-size: 20px;
	font-weight: 500;
	line-height: 1.4;
}

.metric {
	display: flex;
	flex-direction: column;
	gap: 12px;
}

.metric strong {
	font-size: 48px;
	font-weight: 500;
	line-height: 1.167;
	letter-spacing: -1.92px;
}

.metric span {
	font-size: 16px;
	line-height: 1.5;
	color: #505050;
}

.dark .metric span {
	color: #fff;
}

.stars {
	color: #ede87e !important;
	font-size: 22px !important;
	letter-spacing: 2px;
}

.trustAvatars {
	width: 94px;
	height: 36px;
	object-fit: contain;
	flex-shrink: 0;
}

.timerRow span {
	width: 36px;
	height: 36px;
	border-radius: 999px;
	border: 1px solid #fff;
	display: grid;
	place-items: center;
	background: #a0f4d8;
	font-size: 16px;
}

.smallLabel,
.timerRow strong {
	font-size: 12px;
	line-height: 1.333;
	letter-spacing: 1.44px;
	text-align: center;
	font-weight: 400;
	color: #131313;
	white-space: nowrap;
}

.timerRow {
	display: flex;
	align-items: center;
	justify-content: space-between;
	gap: 10px;
}

@media (max-width: 991px) {
	.section {
		padding: 64px 24px;
	}
	.header {
		flex-direction: column;
		align-items: flex-start;
	}
	.header h2 {
		font-size: 48px;
		letter-spacing: -1.92px;
	}
	.grid {
		grid-template-columns: 1fr;
	}
	.tall {
		min-height: 320px;
	}
}

@media (max-width: 767px) {
	.section {
		padding: 48px 16px;
	}
	.header h2 {
		font-size: 40px;
		letter-spacing: -1.6px;
	}
	.card {
		gap: 48px;
	}
	.metric strong {
		font-size: 40px;
	}
}

